          },
          "others": [
            {
              "id": "",
              "url": ""
            }
          ]
        }
      ],
      "status": "",
      "category": [
        {
          "id": "",
          "category": ""
        }
      ],
      "subcategory": "",
      "brand": "",
      "tags": [""],
      "quantity": 0,
      "weight": "",
      "rating": 0,
      "likes": 0,
      "additionalInfo": [],
      "barcode": [],
      "variation": []
    }
  ]
}

 ```

